import React, { useEffect, useState } from 'react';
import axios from 'axios';

const OIDC_CLIENT_ID = 'your-client-id';
const OIDC_REDIRECT_URI = 'http://localhost:3000/callback';
const OIDC_AUTHORIZATION_ENDPOINT = 'https://your-oidc-provider.com/oauth2/authorize';
const OIDC_TOKEN_ENDPOINT = 'https://your-oidc-provider.com/oauth2/token';

const App = () => {
  const [userProfile, setUserProfile] = useState(null);

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    if (code) {
      exchangeCodeForTokens(code);
    }
  }, []);

  const login = () => {
    const state = Math.random().toString(36).substring(2, 15);
    localStorage.setItem('oidcState', state);
    window.location.href = `${OIDC_AUTHORIZATION_ENDPOINT}?client_id=${OIDC_CLIENT_ID}&redirect_uri=${OIDC_REDIRECT_URI}&response_type=code&scope=openid%20profile&state=${state}`;
  };

  const exchangeCodeForTokens = async (code) => {
    const stateFromStorage = localStorage.getItem('oidcState');
    const urlParams = new URLSearchParams(window.location.search);
    const stateFromUrl = urlParams.get('state');

    if (stateFromStorage !== stateFromUrl) {
      console.error('Invalid state parameter');
      return;
    }

    try {
      const response = await axios.post(OIDC_TOKEN_ENDPOINT, {
        grant_type: 'authorization_code',
        code,
        redirect_uri: OIDC_REDIRECT_URI,
        client_id: OIDC_CLIENT_ID
      }, {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      });

      const { id_token } = response.data;
      decodeIdToken(id_token);
    } catch (error) {
      console.error('Error exchanging code for tokens:', error);
    }
  };

  const decodeIdToken = (idToken) => {
    try {
      const base64Url = idToken.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const jsonPayload = decodeURIComponent(atob(base64).split('').map(function(c) {
        return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
      }).join(''));

      setUserProfile(JSON.parse(jsonPayload));
    } catch (error) {
      console.error('Error decoding id token:', error);
    }
  };

  return (
    <div>
      {userProfile ? (
        <div>
          <h1>Welcome, {userProfile.name}!</h1>
          <p>Email: {userProfile.email}</p>
        </div>
      ) : (
        <button onClick={login}>Login</button>
      )}
    </div>
  );
};

export default App;